class Solution {
public:
    vector<string> removeInvalidParentheses(string s) {
        int leftRemove = 0, rightRemove = 0;
        for (char c : s) {
            if (c == '(') leftRemove++;
            else if (c == ')') {
                if (leftRemove > 0) leftRemove--;
                else rightRemove++;
            }
        }

        vector<string> result;
        queue<string> q;
        unordered_set<string> visited;
        q.push(s);
        visited.insert(s);
        bool found = false;

        while (!q.empty()) {
            int size = q.size();
            for (int i = 0; i < size; i++) {
                string curr = q.front();
                q.pop();
                if (isValid(curr)) {
                    found = true;
                    if (leftRemove + rightRemove == 0) result.push_back(curr);
                } else if (!found) {
                    for (int j = 0; j < curr.size(); j++) {
                        if (curr[j] == '(' && leftRemove > 0) {
                            string temp = curr.substr(0, j) + curr.substr(j + 1);
                            if (visited.find(temp) == visited.end()) {
                                q.push(temp);
                                visited.insert(temp);
                                leftRemove--;
                            }
                        } else if (curr[j] == ')' && rightRemove > 0) {
                            string temp = curr.substr(0, j) + curr.substr(j + 1);
                            if (visited.find(temp) == visited.end()) {
                                q.push(temp);
                                visited.insert(temp);
                                rightRemove--;
                            }
                        }
                    }
                }
            }
            if (found) break;
        }
        return result;
    }

    bool isValid(string s) {
        int count = 0;
        for (char c : s) {
            if (c == '(') count++;
            else if (c == ')') {
                count--;
                if (count < 0) return false;
            }
        }
        return count == 0;
    }
};
